module axis_mux #(
  parameter integer C_AXIS_DATA_WIDTH = 32,
  parameter integer C_AXIS_TUSER_WIDTH = 4
) (
  // Define ports for input and output streams.
  input  wire aclk,
  input  wire aresetn,
  input  wire [NUM_INPUTS-1:0]  sel,
  input  wire [NUM_INPUTS-1:0]  in_[NUM_INPUTS]-1:0]  in_[i],
  output wire tvalid.
  output wire tvalid for each stream.
  output wire tvalid.
  output wire tvalid.
  output wire tready.
  output wire tready.
  output wire tready.
  output wire tvalid.
  output wire tvalid.
  output wire tready.
  output wire m_axis_tvalid and tready.
  output wire m_axis_tvalid and tready.
  output wire m_axis_tvalid.
  output wire m_axis_tready.
  output wire m_axis_tvalid and tready.
);

